+    let numpy = py.import("numpy")?;
+    Ok(numpy
+        .getattr("polynomial")?
+        .getattr("chebyshev")?
+        .getattr("chebmul")?
+        .call1((c1.bind(py), c2.bind(py)))?
+        .unbind())
